import { execution } from '@dynatrace-sdk/automation-utils';
import { problemsClient } from '@dynatrace-sdk/client-classic-environment-v2';

export default async function ({ executionId }) {
  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  try {
    let updateBody = {};

    if (input.priorityLevel && input.priorityLevel.trim() !== '') {
      updateBody.priorityLevel = input.priorityLevel;
    }

    if (input.commentText && input.commentText.trim() !== '') {
      await problemsClient.addCommentToProblem({
        problemId: input.problemId,
        body: { comment: input.commentText }
      });
      console.log('Comment added to problem');
    }

    if (Object.keys(updateBody).length > 0) {
      await problemsClient.updateProblem({
        problemId: input.problemId,
        body: updateBody
      });
      console.log('Problem updated');
    }

    return {
      problemId: input.problemId,
      updated: true,
      prioritySet: !!updateBody.priorityLevel,
      commentAdded: !!input.commentText,
      message: 'Problem successfully updated'
    };
  } catch (error) {
    console.error('Error updating problem:', error);
    throw new Error(`Failed to update problem: ${error}`);
  }
}
